body:
When compiling with --hierarchical modules marked as /*verilator hierarchical_blocks*/ can't have IO ports that are of type struct.

Code Example:

```
typedef struct packed {
  logic        vld;
  logic [31:0] count;
} sts_t;

module submodule (
  input wire logic       clk_i,
  input wire logic       rst_n_i,
  output var sts_t       sts_o
); /*verilator hier_block*/ 

  logic[31:0] counter_q;

  always_ff @(posedge clk_i or negedge rst_n_i) begin
    if (!rst_n_i) begin
      counter_q <= 32'b0;
    end
    else begin
      counter_q <= counter_q + 1;

      $display("%m: Counter = 0x%x", counter_q);

      if (counter_q >= 32'hffff)
        $finish;
    end
  end

  always_comb sts_o.vld   = |counter_q;
  always_comb sts_o.count =  counter_q;


endmodule

module dut (
  input wire logic       clk_i,
  input wire logic       rst_n_i
);

  submodule s_u (.clk_i(clk_i),
                 .rst_n_i(rst_n_i),
                 .sts_o()
                );
endmodule
````


```
#ifdef ENV_SIM_VERILATOR
#include <verilated.h>
#include "Vdut.h"
#include "Vdut___024root.h"
#ifdef WAVES
#include "verilated_vcd_c.h"
#endif

int main(int argc, char** argv, char** env) {
    // Prevent unused variable warnings
    if (false && argc && argv && env) {}
    const std::unique_ptr<VerilatedContext> contextp{new VerilatedContext};

    Vdut*             dut  = new Vdut("dut");

#ifdef WAVES
    Verilated::traceEverOn(true);
    VerilatedVcdC* tfp = new VerilatedVcdC;
    dut->trace(tfp, 99);  // Trace 99 levels of hierarchy (or see below)
    tfp->open("waves.vcd");
#endif

    dut->rootp->rst_n_i = 0;
    dut->rootp->clk_i   = 0;

    // Simulate until $finish
    while (!Verilated::gotFinish()) {

        contextp->timeInc(1);

        dut->rootp->clk_i = !dut->clk_i;

        if (!dut->rootp->clk_i) {
            if (contextp->time() > 1 && contextp->time() < 10) {
                dut->rootp->rst_n_i = !1;  // Assert reset
            } else {
                dut->rootp->rst_n_i = !0;  // Deassert reset
            }
        }
        // Evaluate model
        dut->eval();
#ifdef WAVES
        tfp->dump(contextp->time());
#endif
    }

    // Final model cleanup
    dut->final();

    // Destroy model
    delete dut;

    // Return good completion status
    return 0;
}
#endif
````

```
non_hier: dut.sv tb.cpp
	verilator --exe -cc -CFLAGS "-DENV_SIM_VERILATOR" -timescale 1ns/1ps dut.sv tb.cpp
	make -C obj_dir/ -f Vdut.mk
	./obj_dir/Vdut

hier: dut.sv tb.cpp
	verilator --exe -cc -hierarchical -CFLAGS "-DENV_SIM_VERILATOR" -timescale 1ns/1ps dut.sv tb.cpp
	make -C obj_dir/ -f Vdut.mk
	./obj_dir/Vdut

clean:
	rm -rf obj_dir
```
